import json

def calculate_average_effectiveness(feedback, treatment_name):
    # Filter feedback for the specified treatment
    filtered_feedback = [patient for patient in feedback if treatment_name in patient["treatments"]]

    # Calculate the sum of effectiveness ratings
    total = sum(patient["treatments"][treatment_name] for patient in filtered_feedback)

    # Count the number of patients who provided feedback
    count = len(filtered_feedback)

    # If no patients provided feedback, return 0.0
    if count == 0:
        return 0.0

    # Calculate the average
    average = total / count

    # Round to two decimal places
    return round(average, 2)

# Example usage
